import React, { useState, useEffect, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import { doctorAPI, appointmentAPI } from '../services/api';
import { getErrorMessage } from '../utils/helpers';
import AppointmentCard from '../components/AppointmentCard';
import './DashboardPages.css';

const DoctorPage = ({ showToast }) => {
  const [profile, setProfile] = useState(null);
  const [appointments, setAppointments] = useState([]);
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState('profile');
  const [formData, setFormData] = useState({
    specialization: '',
    department: '',
    qualifications: '',
    experience_years: '',
    biography: '',
    image: '',
  });
  const { user, logout } = useContext(AuthContext);
  const navigate = useNavigate();

  useEffect(() => {
    loadProfile();
    loadAppointments();
  }, []);

  const loadProfile = async () => {
    try {
      const data = await doctorAPI.getMe();
      setProfile(data);
      setFormData({
        specialization: data.specialization || '',
        department: data.department || '',
        qualifications: data.qualifications || '',
        experience_years: data.experience_years || '',
        biography: data.biography || '',
        image: data.image || '',
      });
    } catch (error) {
      showToast(getErrorMessage(error), 'error');
    }
  };

  const loadAppointments = async () => {
    try {
      const data = await appointmentAPI.getAll();
      setAppointments(data.appointments || []);
    } catch (error) {
      console.error(error);
    }
  };

  const handleFormChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleUpdateProfile = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      await doctorAPI.updateMe(formData);
      showToast('Profile updated successfully!', 'success');
      loadProfile();
    } catch (error) {
      showToast(getErrorMessage(error), 'error');
    } finally {
      setLoading(false);
    }
  };

  const handleCompleteAppointment = async (appointmentId) => {
    try {
      await appointmentAPI.complete(appointmentId);
      showToast('Appointment marked as completed!', 'success');
      loadAppointments();
    } catch (error) {
      showToast(getErrorMessage(error), 'error');
    }
  };

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <div className="dashboard-page">
      <header className="header">
        <div className="header-content">
          <h1>Doctor Dashboard</h1>
          <div className="header-right">
            <div className="user-info">
              Logged in as <strong>{user?.name}</strong> ({user?.role})
            </div>
            <button className="logout-btn" onClick={handleLogout}>
              Logout
            </button>
          </div>
        </div>
      </header>

      <div className="container">
        <div className="page-content">
          <div className="tabs">
            <button
              className={`tab-btn ${activeTab === 'viewprofile' ? 'active' : ''}`}
              onClick={() => setActiveTab('viewprofile')}
            >
              View Profile
            </button>
            <button
              className={`tab-btn ${activeTab === 'editprofile' ? 'active' : ''}`}
              onClick={() => setActiveTab('editprofile')}
            >
              Edit Profile
            </button>
            <button
              className={`tab-btn ${activeTab === 'appointments' ? 'active' : ''}`}
              onClick={() => setActiveTab('appointments')}
            >
              Appointments ({appointments.length})
            </button>
          </div>

          {activeTab === 'viewprofile' && (
            <div className="section">
              <h2>My Profile</h2>
              {profile ? (
                <div className="profile-view">
                  <div className="profile-header">
                    {profile.image && (
                      <img src={profile.image} alt={profile.name} className="profile-image" />
                    )}
                    <div className="profile-info">
                      <h3>{profile.name}</h3>
                      <p className="email">{profile.email}</p>
                      <p className="phone">{profile.phone}</p>
                      <p className={`status ${profile.is_approved ? 'approved' : 'pending'}`}>
                        Status: {profile.is_approved ? 'Approved' : 'Pending Approval'}
                      </p>
                    </div>
                  </div>

                  <div className="profile-details">
                    <div className="detail-group">
                      <label>Specialization:</label>
                      <p>{profile.specialization || 'Not specified'}</p>
                    </div>
                    <div className="detail-group">
                      <label>Department:</label>
                      <p>{profile.department || 'Not specified'}</p>
                    </div>
                    <div className="detail-group">
                      <label>Qualifications:</label>
                      <p>{profile.qualifications || 'Not specified'}</p>
                    </div>
                    <div className="detail-group">
                      <label>Years of Experience:</label>
                      <p>{profile.experience_years || 'Not specified'}</p>
                    </div>
                    <div className="detail-group">
                      <label>Address:</label>
                      <p>{profile.address || 'Not specified'}</p>
                    </div>
                    <div className="detail-group">
                      <label>Biography:</label>
                      <p>{profile.biography || 'Not specified'}</p>
                    </div>
                  </div>
                </div>
              ) : (
                <div className="loading">Loading profile...</div>
              )}
            </div>
          )}

          {activeTab === 'editprofile' && (
            <div className="section">
              <h2>Edit Profile</h2>
              <form onSubmit={handleUpdateProfile}>
                <div className="form-group">
                  <label htmlFor="specialization">Specialization</label>
                  <input
                    id="specialization"
                    type="text"
                    name="specialization"
                    value={formData.specialization}
                    onChange={handleFormChange}
                    placeholder="e.g., Cardiology"
                  />
                </div>

                <div className="form-group">
                  <label htmlFor="department">Department</label>
                  <input
                    id="department"
                    type="text"
                    name="department"
                    value={formData.department}
                    onChange={handleFormChange}
                    placeholder="e.g., Cardiology Department"
                  />
                </div>

                <div className="form-group">
                  <label htmlFor="qualifications">Qualifications</label>
                  <input
                    id="qualifications"
                    type="text"
                    name="qualifications"
                    value={formData.qualifications}
                    onChange={handleFormChange}
                    placeholder="e.g., M.D., B.S."
                  />
                </div>

                <div className="form-group">
                  <label htmlFor="experience_years">Years of Experience</label>
                  <input
                    id="experience_years"
                    type="number"
                    name="experience_years"
                    value={formData.experience_years}
                    onChange={handleFormChange}
                    placeholder="e.g., 10"
                  />
                </div>

                <div className="form-group">
                  <label htmlFor="biography">Biography</label>
                  <textarea
                    id="biography"
                    name="biography"
                    value={formData.biography}
                    onChange={handleFormChange}
                    placeholder="Tell us about yourself..."
                  />
                </div>

                <div className="form-group">
                  <label htmlFor="image">Image URL</label>
                  <input
                    id="image"
                    type="url"
                    name="image"
                    value={formData.image}
                    onChange={handleFormChange}
                    placeholder="https://example.com/image.jpg"
                  />
                </div>

                <button type="submit" className="btn-primary" disabled={loading}>
                  {loading ? 'Updating...' : 'Update Profile'}
                </button>
              </form>
            </div>
          )}

          {activeTab === 'appointments' && (
            <div className="section">
              <h2>My Appointments</h2>
              {appointments.length === 0 ? (
                <div className="no-data">No appointments yet</div>
              ) : (
                <div className="appointments-list">
                  {appointments.map((appointment) => (
                    <AppointmentCard
                      key={appointment.id}
                      appointment={appointment}
                      userRole="doctor"
                      onComplete={handleCompleteAppointment}
                    />
                  ))}
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default DoctorPage;
